INSERT INTO drugs (chinese_name, chinese_characters, latin_name, french_name, nature, dosage, additional_notes, number_of_stars, category_id) VALUES ('Dong gua ren', '冬瓜仁/冬瓜子', NULL, NULL, 'COLD', '9 à 15g par jour', 'Aussi connu sous le nom Dong gua zi (冬瓜子). Appartient à la catégorie des ingrédients qui font s''écouler l''eau, réduisent les œdèmes et les gonflements. Utilisé dans Wei jing tang (avec Lu gen, Tao ren, Yi yi ren) et dans Da huang mu dan tang (avec Da huang, Mu dan pi). Utilisé avec Huang bai, Bi xie etc. pour les leucorrhées et lin de graisse.', 0, (SELECT id FROM drug_category WHERE name = 'Ingrédients qui font s’écouler l’eau, réduisent les œdèmes et les gonflements')) ON CONFLICT (chinese_name) DO NOTHING;
