INSERT INTO drugs (chinese_name, chinese_characters, latin_name, french_name, nature, dosage, additional_notes, number_of_stars, category_id) VALUES ('Fan hong hua', '番紅花', 'Crocus sativus L.', 'Safran', 'COLD', '1 à 1,5g', 'Aussi appelé Zang hong hua (藏紅花). Indications : douleurs menstruelles du post-partum, traumatologie, induration douloureuse de l''épigastre, macules et papules suite à une maladie fébrile. Fait partie de la catégorie des ingrédients qui activent le sang et régularisent les règles (Huo xue tiao jing yao 活血調經藥). Présenté en annexe.', 0, (SELECT id FROM drug_category WHERE name = 'Ingrédients qui activent le sang et régularisent les règles')) ON CONFLICT (chinese_name) DO NOTHING;
