INSERT INTO drug_association (drug_id, associated_drug_id) SELECT d.id, p.id FROM drugs d JOIN drugs p ON p.chinese_name = 'E jiao' WHERE d.chinese_name = 'Da zao'   AND NOT EXISTS (SELECT 1 FROM drug_association WHERE drug_id = d.id AND associated_drug_id = p.id);
INSERT INTO drug_association_effects (association_id, effect) SELECT da.id, 'Nourrissent le Sang et Yingqi, arrêtent les saignements.' FROM drug_association da JOIN drugs d ON d.id = da.drug_id AND d.chinese_name = 'Da zao' JOIN drugs p ON p.id = da.associated_drug_id AND p.chinese_name = 'E jiao' WHERE NOT EXISTS (SELECT 1 FROM drug_association_effects WHERE association_id = da.id AND effect = 'Nourrissent le Sang et Yingqi, arrêtent les saignements.');
