INSERT INTO drug_association_effects (association_id, effect) SELECT da.id, 'Associé à Ge gen, Bai dou kou, Sha ren etc. dans les cas d''intoxication à l''alcool pour son effet antitoxique' FROM drug_association da JOIN drugs d ON d.id = da.drug_id AND d.chinese_name = 'Bai bian dou' JOIN drugs p ON p.id = da.associated_drug_id AND p.chinese_name = 'Ge gen' WHERE NOT EXISTS (SELECT 1 FROM drug_association_effects WHERE association_id = da.id AND effect = 'Associé à Ge gen, Bai dou kou, Sha ren etc. dans les cas d''intoxication à l''alcool pour son effet antitoxique');
